    {
        foreach (InvoiceSuiteCodelistAllowanceChargeCodes::cases() as $c) {
            yield 'InvoiceSuiteCodelistAllowanceChargeCodes:'.$c->name => [InvoiceSuiteCodelistAllowanceChargeCodes::class, $c->value];
